import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import axios from 'axios';

const Login = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      const res = await axios.post('http://localhost:5000/api/auth/login', { email, password });
      localStorage.setItem('token', res.data.token);
      navigate('/dashboard');
    } catch (err) {
      setError(err?.response?.data?.error || 'Login failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="login-page">
      <div className="login-container">
        <div className="login-card">
          <div className="login-header">
            <div className="login-logo">💼</div>
            <h1>Charity Wallet</h1>
            <p>Secure crypto management</p>
          </div>

          <form className="login-form" onSubmit={handleSubmit}>
            <div className="form-group">
              <label htmlFor="email">Email Address</label>
              <input 
                id="email"
                type="email" 
                placeholder="your@email.com" 
                value={email} 
                onChange={(e) => setEmail(e.target.value)} 
                required 
              />
            </div>

            <div className="form-group">
              <label htmlFor="password">Password</label>
              <input 
                id="password"
                type="password" 
                placeholder="••••••••" 
                value={password} 
                onChange={(e) => setPassword(e.target.value)} 
                required 
              />
            </div>

            {error && <div className="error-message">{error}</div>}

            <button type="submit" className="btn-login" disabled={loading}>
              {loading ? (
                <><span className="spinner"></span> Logging in...</>
              ) : (
                <>Sign In</>
              )}
            </button>
          </form>

          <div className="login-divider">Don't have an account?</div>
          
          <Link to="/register" className="btn-register">Create new account</Link>
        </div>

        <div className="login-features">
          <div className="feature">
            <span className="feature-icon">🔒</span>
            <h3>Secure</h3>
            <p>Bank-level encryption</p>
          </div>
          <div className="feature">
            <span className="feature-icon">⚡</span>
            <h3>Fast</h3>
            <p>Instant transactions</p>
          </div>
          <div className="feature">
            <span className="feature-icon">🌍</span>
            <h3>Global</h3>
            <p>Support worldwide</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Login;
